"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["96673"],{81809(e){e.exports=JSON.parse('{"tag":{"label":"messaging","permalink":"/sysanalyst-kb.github.io/tech/tags/messaging","allTagsPath":"/sysanalyst-kb.github.io/tech/tags","count":5,"items":[{"id":"kafka","title":"Apache Kafka","description":"Kafka \u2014 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u0430\u044F \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u0434\u043B\u044F \u0441\u043E\u0431\u044B\u0442\u0438\u0439\u043D\u044B\u0445 \u043F\u043E\u0442\u043E\u043A\u043E\u0432 (event streaming). \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \u043A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0431\u0440\u043E\u043A\u0435\u0440\u043E\u0432 (RabbitMQ), Kafka \u043D\u0435 \u0443\u0434\u0430\u043B\u044F\u0435\u0442 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F \u043F\u043E\u0441\u043B\u0435 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438, \u0430 \u0445\u0440\u0430\u043D\u0438\u0442 \u0438\u0445 \u0432 \u0436\u0443\u0440\u043D\u0430\u043B\u0435 (log) \u0441 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0435\u0440\u0435\u0447\u0438\u0442\u044B\u0432\u0430\u0442\u044C.","permalink":"/sysanalyst-kb.github.io/tech/kafka"},{"id":"iso20022","title":"ISO 20022 \u2014 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0435 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F","description":"ISO 20022 \u2014 \u043C\u0435\u0436\u0434\u0443\u043D\u0430\u0440\u043E\u0434\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u0434\u043B\u044F \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0433\u043E \u043E\u0431\u043C\u0435\u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u043C\u0438 \u0438\u043D\u0441\u0442\u0438\u0442\u0443\u0442\u0430\u043C\u0438. \u0417\u0430\u043C\u0435\u043D\u044F\u0435\u0442 \u0441\u0442\u0430\u0440\u044B\u0435 \u0444\u043E\u0440\u043C\u0430\u0442\u044B (MT \u2014 \u0432 SWIFT, UFE/STM \u2014 \u0432 \u043D\u0430\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0445).","permalink":"/sysanalyst-kb.github.io/tech/iso20022"},{"id":"rabbitmq","title":"RabbitMQ","description":"RabbitMQ \u2014 \u0431\u0440\u043E\u043A\u0435\u0440 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439, \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u044E\u0449\u0438\u0439 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B AMQP 0-9-1. \u042D\u0442\u043E \u043A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u0438\u0439 message broker: \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0435 \u043F\u043E\u043F\u0430\u0434\u0430\u0435\u0442 \u0432 \u043E\u0447\u0435\u0440\u0435\u0434\u044C \u0438 \u0436\u0434\u0451\u0442, \u043F\u043E\u043A\u0430 consumer \u0435\u0433\u043E \u0437\u0430\u0431\u0435\u0440\u0451\u0442. \u041F\u043E\u0441\u043B\u0435 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0435 \u0443\u0434\u0430\u043B\u044F\u0435\u0442\u0441\u044F.","permalink":"/sysanalyst-kb.github.io/tech/rabbitmq"},{"id":"swift","title":"SWIFT \u2014 \u043C\u0435\u0436\u0431\u0430\u043D\u043A\u043E\u0432\u0441\u043A\u0438\u0435 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F","description":"SWIFT (Society for Worldwide Interbank Financial Telecommunication) \u2014 \u0433\u043B\u043E\u0431\u0430\u043B\u044C\u043D\u0430\u044F \u0441\u0435\u0442\u044C \u0434\u043B\u044F \u043F\u0435\u0440\u0435\u0434\u0430\u0447\u0438 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0445 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439 \u043C\u0435\u0436\u0434\u0443 \u0431\u0430\u043D\u043A\u0430\u043C\u0438.","permalink":"/sysanalyst-kb.github.io/tech/swift"},{"id":"websocket","title":"WebSocket / SSE \u2014 real-time \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u044B","description":"WebSocket \u2014 full-duplex \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B \u043F\u043E\u0432\u0435\u0440\u0445 TCP (RFC 6455) \u0434\u043B\u044F real-time \u043A\u043E\u043C\u043C\u0443\u043D\u0438\u043A\u0430\u0446\u0438\u0439 (\u0447\u0430\u0442\u044B, \u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u044F, \u043A\u043E\u043B\u043B\u0430\u0431\u043E\u0440\u0430\u0446\u0438\u044F, live-\u0441\u0442\u0440\u0438\u043C\u044B). SSE (Server-Sent Events) \u2014 \u043E\u0434\u043D\u043E\u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B \u043E\u0442 \u0441\u0435\u0440\u0432\u0435\u0440\u0430 \u043A \u043A\u043B\u0438\u0435\u043D\u0442\u0443 (\u043B\u0435\u043D\u0442\u0430, \u0442\u0438\u043A\u0435\u0440\u044B, \u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u044F). Long Polling \u2014 fallback \u0434\u043B\u044F \u0431\u0440\u0430\u0443\u0437\u0435\u0440\u043E\u0432 \u0431\u0435\u0437 WebSocket. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0432\u044B\u0431\u0438\u0440\u0430\u0435\u0442 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B \u043F\u043E\u0434 \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0439 Discord (WebSocket Gateway), Telegram (MTProto), Signal (WebSocket), Slack (WebSocket RTM).","permalink":"/sysanalyst-kb.github.io/tech/websocket"}],"unlisted":false}}')}}]);